/// <summary>
/// Event handler class for the <c>PurchAgreement</c> form for the ETG model.
/// </summary>
class PurchAgreementETGSPAINEventHandler
{        
}

Method.Source:
/// <summary>
/// Clicked method for the "Contract by Quotas" checkbox.
/// </summary>
/// <param name="sender">"Contract by Quotas" checkbox.</param>
/// <param name="e">Event arguments.</param>
[FormControlEventHandler(formControlStr(PurchAgreement, PurchAgreementHeader_ETGSPAINPurchHasAgreementQuotas), FormControlEventType::Clicked)]
public static void PurchAgreementHeader_ETGPurchHasAgreementQuotas_OnClicked(FormControl sender, FormControlEventArgs e)
{
    Args                    args                    = new Args();
    FormRun                 formRun                 = sender.formRun();        
    FormDataSource          purchAgreementHeader_DS = formRun.dataSource(formDataSourceStr(PurchAgreement, PurchAgreementHeader));
    FormDataSource          purchAgreementLine_DS = formRun.dataSource(formDataSourceStr(PurchAgreement, ALine));
    PurchAgreementHeader    purchAgreementHeader    = purchAgreementHeader_DS.cursor();
    AgreementHeader         agreementHeader         = AgreementHeader::find(purchAgreementHeader.RecId);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (purchAgreementHeader.ETGSPAINPurchHasAgreementQuotas)
        {
            // Lanzamos proceso de Contrato por Cupos
            args.record(agreementHeader);
            args.caller(formRun);

            new MenuFunction(menuItemActionStr(ETGSPAINPurchSalesAgreementQuotaDialog), MenuItemType::Action).run(args);
        }
        else
        {
            // Reseteamos los valores de Cupos
            ttsbegin;
            agreementHeader.selectForUpdate(true);
            agreementHeader.ETGSPAINresetAgreementQuota();
            agreementHeader.update();
            ttscommit;
        }

        // Refresco de la cabecera del formulario
        purchAgreementHeader_DS.refresh();

        // Refrescamos los datos de las líneas
        purchAgreementLine_DS.refresh();
    }
}
